const domains = ['example.com', 'api.example.com'];
const results = [];

for (const domain of domains) {
  try {
    const response = await this.helpers.httpRequest({
      url: `https://crt.sh/?q=${domain}&output=json`,
      method: 'GET',
      returnFullResponse: true
    });

    const certs = JSON.parse(response.body);
    if (certs && certs.length > 0) {
      const latestCert = certs[0];
      const expiryDate = new Date(latestCert.not_after);
      const daysUntilExpiry = Math.floor((expiryDate - new Date()) / (1000 * 60 * 60 * 24));

      results.push({
        domain: domain,
        expiryDate: expiryDate.toISOString(),
        daysUntilExpiry: daysUntilExpiry,
        issuer: latestCert.issuer_name,
        needsAlert: daysUntilExpiry <= 30
      });
    }
  } catch (error) {
    results.push({
      domain: domain,
      error: error.message,
      needsAlert: true
    });
  }
}

return results.map(item => ({ json: item }));

